effect channel[T] {
    f send(val: T);
    f recv() -> ?T;
}

+f produce_consume() -> [i32]~ / async, channel[i32] {
    v producer = async.spawn(fn() {
        m i: i32 = 0;
        loop {
            ? i >= 5 { break; }
            channel.send(i);
            i = i + 1;
        }
    });
    m results: [i32]~ = [];
    loop {
        v val = channel.recv();
        ? val { ?Some(v) => results.push(v), ?None => break }
    }
    async.join(producer);
    results
}

rust_equivalent.rs_source:
use std::sync::mpsc;
use std::thread;

pub fn produce_consume() -> Vec<i32> {
    let (tx, rx) = mpsc::channel();
    let producer = thread::spawn(move || {
        for i in 0..5 {
            tx.send(i).unwrap();
        }
    });
    let mut results = Vec::new();
    for val in rx {
        results.push(val);
    }
    producer.join().unwrap();
    results
}

