use std::thread;

pub fn par_map<T: Send + 'static, U: Send + 'static>(
    items: Vec<T>,
    func: fn(T) -> U,
) -> Vec<U> {
    let handles: Vec<_> = items
        .into_iter()
        .map(|item| thread::spawn(move || func(item)))
        .collect();
    handles.into_iter().map(|h| h.join().unwrap()).collect()
}

