S Locked[T] { inner: @Mutex[T] }

I Locked[T] {
    +f new(val: T) -> Locked[T] { @Locked { inner: @Mutex.new(val) } }
    +f with(&self, func: f(&!T)) { v guard = self.inner.lock(); func(&!guard); }
}

+f accumulate(vals: [i32]~) -> i32 / async {
    v acc = Locked.new(0);
    m handles: [Handle[()]]~ = [];
    @ val : vals {
        v ref_acc = acc.clone();
        handles.push(async.spawn(fn() {
            ref_acc.with(fn(total: &!i32) { *total = *total + val; });
        }));
    }
    @ h : handles { async.join(h); }
    v result: i32 = 0;
    acc.with(fn(total: &!i32) { result = *total; });
    result
}

rust_equivalent.rs_source:
use std::sync::{Arc, Mutex};
use std::thread;

pub fn accumulate(vals: Vec<i32>) -> i32 {
    let acc = Arc::new(Mutex::new(0));
    let handles: Vec<_> = vals.into_iter().map(|val| {
        let acc = Arc::clone(&acc);
        thread::spawn(move || {
            let mut guard = acc.lock().unwrap();
            *guard += val;
        })
    }).collect();
    for h in handles { h.join().unwrap(); }
    *acc.lock().unwrap()
}

