effect timer {
    f sleep(ms: u64);
    f deadline(ms: u64) -> Handle[()];
}

+f with_timeout[T](ms: u64, task: f() -> T) -> ?T / async, timer {
    v cancel = timer.deadline(ms);
    v work = async.spawn(task);
    ? async.select(work, cancel) {
        Left(result) => ?Some(result),
        Right(_) => ?None,
    }
}

rust_equivalent.rs_source:
use tokio::time::{timeout, Duration};

pub async fn with_timeout<T: Send + 'static>(
    ms: u64,
    task: impl std::future::Future<Output = T> + Send + 'static,
) -> Option<T> {
    match timeout(Duration::from_millis(ms), task).await {
        Ok(result) => Some(result),
        Err(_) => None,
    }
}

