rust_equivalent.rs_source:
use std::sync::atomic::{AtomicI64, Ordering};
use std::sync::Arc;

struct RateLimiter {
    tokens: Arc<AtomicI64>,
    max_tokens: i64,
    refill_rate: i64,
}

impl RateLimiter {
    pub fn new(max: i64, rate: i64) -> Self {
        Self { tokens: Arc::new(AtomicI64::new(max)), max_tokens: max, refill_rate: rate }
    }
    pub fn try_acquire(&self) -> bool {
        let current = self.tokens.load(Ordering::SeqCst);
        if current > 0 { self.tokens.fetch_sub(1, Ordering::SeqCst); true } else { false }
    }
    pub fn refill(&self) {
        let current = self.tokens.load(Ordering::SeqCst);
        if current < self.max_tokens { self.tokens.fetch_add(self.refill_rate, Ordering::SeqCst); }
    }
}

