S Barrier {
    count: @AtomicI64,
    target: i64,
}

I Barrier {
    +f new(n: i64) -> Barrier {
        @Barrier { count: @AtomicI64.new(0), target: n }
    }
    +f arrive_and_wait(&self) / async {
        v arrived = self.count.fetch_add(1) + 1;
        ? arrived >= self.target {
            // last arrival — all proceed
        } : {
            loop {
                ? self.count.load() >= self.target { break; }
                async.yield();
            }
        }
    }
}

