+f map_reduce(
    data: [i32]~,
    chunk_size: usize,
    mapper: f(i32) -> i64,
    reducer: f(i64, i64) -> i64,
    init: i64,
) -> i64 / async {
    m handles: [Handle[i64]]~ = [];
    m start: usize = 0;
    loop {
        ? start >= data.len() { break; }
        v end: usize = ? start + chunk_size > data.len() { data.len() } : { start + chunk_size };
        v chunk = data[start..end].to_vec();
        handles.push(async.spawn(fn() {
            m acc: i64 = init;
            @ val : chunk { acc = reducer(acc, mapper(val)); }
            acc
        }));
        start = start + chunk_size;
    }
    m result: i64 = init;
    @ h : handles { result = reducer(result, async.join(h)); }
    result
}

rust_equivalent.rs_source:
use std::thread;

pub fn map_reduce(
    data: Vec<i32>,
    chunk_size: usize,
    mapper: fn(i32) -> i64,
    reducer: fn(i64, i64) -> i64,
    init: i64,
) -> i64 {
    let handles: Vec<_> = data.chunks(chunk_size).map(|chunk| {
        let chunk = chunk.to_vec();
        thread::spawn(move || {
            chunk.into_iter().fold(init, |acc, val| reducer(acc, mapper(val)))
        })
    }).collect();
    handles.into_iter().fold(init, |acc, h| reducer(acc, h.join().unwrap()))
}

