S Semaphore {
    permits: @AtomicI64,
    max_permits: i64,
}

I Semaphore {
    +f new(n: i64) -> Semaphore {
        @Semaphore { permits: @AtomicI64.new(n), max_permits: n }
    }
    +f acquire(&self) / async {
        loop {
            v current = self.permits.load();
            ? current > 0 {
                self.permits.fetch_sub(1);
                ret;
            }
            async.yield();
        }
    }
    +f release(&self) {
        v current = self.permits.load();
        ? current < self.max_permits {
            self.permits.fetch_add(1);
        }
    }
}

rust_equivalent.rs_source:
use tokio::sync::Semaphore as TokioSemaphore;
use std::sync::Arc;

struct Semaphore { inner: Arc<TokioSemaphore> }

impl Semaphore {
    pub fn new(n: usize) -> Self {
        Self { inner: Arc::new(TokioSemaphore::new(n)) }
    }
    pub async fn acquire(&self) {
        self.inner.acquire().await.unwrap().forget();
    }
    pub fn release(&self) {
        self.inner.add_permits(1);
    }
}
